export const ZONES_BEST_REGIONS = {"KAOLACK": 103, "KEDOUGOU": 89, "KOLDA": 576, "SEDHIOU": 128, "TAMBACOUNDA": 92, "ZIGUINCHOR": 53} as const;

/** Lots d'allotissement (avec compte). */
export const ZONES_BEST_LOTS = {"LOT 1": 445, "LOT 2": 312, "LOT 3": 284} as const;

/** Mappe le statut texte de la liste BEST → StatutZone du store. */
function mapStatutBEST(s: string): 'non_demarre' | 'en_cours' | 'termine' | 'suspendu' {
  const t = (s || '').toLowerCase();
  if (t.includes('termin') || t.includes('récep') || t.includes('recep') || t.includes('achev') || t.includes('mes')) return 'termine';
  if (t.includes('cours') || t.includes('encours')) return 'en_cours';
  if (t.includes('suspend') || t.includes('arrêt') || t.includes('arret')) return 'suspendu';
  return 'non_demarre';
}

/**
 * Convertit les 1041 localités BEST en lignes de zones (ZoneRow) pour le module
 * Zones & Quantités. `lot` optionnel pour ne charger qu'un allotissement (LOT 1/2/3).
 */
export function zonesBESTToRows(lot?: string): Array<{
  id: string; code: string; localite: string; region: string; departement: string;
  cav: string; cacrv: string; commune: string; lot: string; lat?: number; lng?: number;
  statut: 'non_demarre' | 'en_cours' | 'termine' | 'suspendu'; observation: string;
}> {
  return ZONES_BEST
    .filter(z => !lot || z.lot === lot)
    .map((z, i) => ({
      id: `best_${z.code || i}`,
      code: z.code || `BEST-${i + 1}`,
      localite: z.localite,
      region: z.region,
      departement: z.departement,
      cav: z.cav,
      cacrv: z.cacrv,
      commune: z.cacrv || z.cav,
      lot: z.lot,
      lat: z.lat ?? undefined,
      lng: z.lng ?? undefined,
      statut: mapStatutBEST(z.statut),
      observation: z.statut || '',
    }));
}
